1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	
11	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM_BY_TYPE[item.type];
12	
13	export function quote(_customer: { yearsWithMHPCO: number }, items: { type: string }[]): number {
14	  const itemsTotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
15	  return itemsTotal + PROCESSING_FEE;
16	}
17	
18	export function claim(): number {
19	  return undefined as unknown as number;
20	}
